var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"於是你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"와아, 언제 봐도 으리으리한 방이네.","JPN":"すごい……いつ見てもデカい部屋だね。","ENG":"Wow, this fancy room never fails to impress me.","TWN":"哇啊，不管什麼時候看，這裡都是個氣派莊嚴的房間呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"천장 높고, 환기도 잘 되는 거 같고......","JPN":"天井が高いし、風通しも良くて……","ENG":"It's got that high ceiling, and nice ventilation too...","TWN":"高高的天花板，通風好像也不錯……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"이런 곳에서 살려면 원룸이라도 월세가 엄청 비싸겠지?","JPN":"こんなところに住もうとすると、ワンルームでも相当家賃が高いだろうね。","ENG":"I bet it'll cost a fortune to live in a cushy place like this, huh?","TWN":"建在這樣的地段，即使是套房，月租肯定也很貴吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"......앗! 내 정신 좀 봐. 그러고 보니 난 무슨 일로 불렀어?","JPN":"……あっ！こうしてる場合じゃない。そういえば、何で私を呼んだの？","ENG":"Oh! Where are my manners. So what did you need to see me for anyway?","TWN":"……啊！看看我這腦袋，話說回來，你找我有什麼事嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"어? 평생고용보장?","JPN":"え？終身契約？","ENG":"Huh? Lifetime job security?","TWN":"什麼？終身雇傭保證？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"나야 좋긴 한데, 정말 괜찮겠어?","JPN":"私はいいけど、本当にいいの？","ENG":"Sure, I'd love that. But are you sure?","TWN":"我當然是好了，不過真的沒關係嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"아니, 아니! 내가 싫다는 건 절대로 아니고...... 으음......","JPN":"い、いや！　私が嫌なわけじゃなくて……うーん……","ENG":"Oh, no, no... I'm not saying that I don't like the idea at all! Hmm....","TWN":"沒有，沒有！絕對不是不喜歡啦……呃嗯……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"요즘 불경기에 고용불안이다 뭐다 얘기가 많잖아.","JPN":"最近、不景気で雇用不安やらいろいろ話題になってるからさ。","ENG":"It's just that, there's all that talk about the economy and unstable job security.","TWN":"因為最近不景氣，有很多人失業不是嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"이렇게 나 혼자만 이런 혜택을 받아도 괜찮나 싶어서 말이지.","JPN":"こうして私だけいい思いしてもいいのかなって。","ENG":"I was just wondering if I really deserve all this when everyone's going through a rough time.","TWN":"就我一個人享有這樣的好處，真的沒關係吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"하하......","JPN":"はは……","ENG":"Hah hah...","TWN":"哈哈……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"난 말이지.","JPN":"私はね。","ENG":"You see...","TWN":"我啊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"언니가 쓰러진 뒤로, 줄곧 혼자서만 싸워왔어.","JPN":"姉さんが倒れてから、ずっと一人で戦ってきた。","ENG":"I've always been fighting on my own ever since my sister collapsed.","TWN":"自從姐姐倒下後，我就一直是一個人戰鬥。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"언니가 깨어나지 못하면 영영 혼자가 될까 겁이 나서,","JPN":"姉さんがこのまま目が覚めなくて、ひとりぼっちになるのが怖くて、","ENG":"I was scared that I'd be all alone if she never wakes up.","TWN":"我害怕要是姐姐沒辦法醒來，我就永遠變成一個人了，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"그저 무작정 달렸어.","JPN":"ひたすら走り続けてきた。","ENG":"So I just kept running with my eyes set in front of me.","TWN":"所以我只是一味地往前衝。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"그런데 여기 온 뒤로 그 생각이 변하게 된 거야.","JPN":"なのにここに来てから、その考えが変わったの。","ENG":"But ever since I got here, I changed my mind.","TWN":"可是來到這裡以後，我的想法改變了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"시작부터 믿었던 사람한테 뒤통수를 맞거나, 일이 꼬인 적도 여러 차례지만......","JPN":"信じていた人に裏切られたり、仕事がうまくいかなかったこともたくさんあったけど……","ENG":"Sure, I got stabbed in the back right from the get-go, and I went through a ton of other messed up stuff...","TWN":"一開始就被信任的人背叛，好多次工作都不順利……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"바보 같은 날 지켜주고, 끝까지 믿어주는 사람들이 있어서, 앞만 보던 내가 점점 주위를 둘러보게 되더라고.","JPN":"バカみたいな私を守ってくれて、いつまでも信じてくれてる人たちがいるから、前ばかり見ていた私も周りを見るようになってた。","ENG":"But there were also people who kept me safe and counted on me till the very end. So I eventually learned to look around me.","TWN":"但因為有那些保護愚蠢的我，並相信我到最後的人，一直以來只懂向前看的我，漸漸地也看見了周圍的人事物。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"그때부터 더는 엄살 피우지 않기로 결심했어.","JPN":"あの時から、もう弱音を吐かないって決めたんだ。","ENG":"So I stopped feeling so sorry for myself.","TWN":"從那時候開始，我就下定決心不再惹麻煩。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"혼자인 줄 알았던 내가 누군가를 의지하고, 또 누군가에게 의지 받는단 사실이......","JPN":"ひとりぼっちだと思ってた私が、人に頼ったり頼られたりする事が……","ENG":"The fact that I could rely on someone, and that someone could rely on me...","TWN":"以為自己是一個人的我依賴別人，又被別人依賴這種事……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"내겐 정말 각별했거든.","JPN":"私にとっては嬉しかったの。","ENG":"It was really special for me.","TWN":"對我來說真的很特別。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"솔직히 이 회사가 왜 소문도 좋지 않던 나를 그렇게 간단히 받아들여줬는지, 지금도 잘 모르겠어.","JPN":"正直、この会社がどうして悪い噂ばかりの私を\\n簡単に受け入れてくれたのか、いまだにわからない。","ENG":"Honestly, I still don't understand why this company accepted me so easily, especially given my terrible reputation at the time.","TWN":"說實話，這家公司為什麼會那麼輕易地就接受傳聞不好的我，到現在我還是不知道。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"어쩌면 사장님은 처음부터 이렇게 될 줄 알고 있었던 걸까?","JPN":"もしかしたら、社長はこうなるって最初からわかってたの？","ENG":"Or maybe you knew it'd be like this all along?","TWN":"大概是老闆從一開始就知道會變成這樣吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"하긴......","JPN":"まあでも……","ENG":"I suppose...","TWN":"也是……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"이 모든 게 우연이었는지 아닌진 별로 중요하지 않겠지.","JPN":"このすべてが偶然だったのかどうかは別に重要じゃない。","ENG":"Whether this was all a coincidence or not might not be that important.","TWN":"不管這一切是不是偶然，都已經不重要了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"하지만 그 덕분에, 난 어쩌면 평생 경험하지 못할 수 있었던 일들을 겪었고......","JPN":"おかげで、私は一生経験できないかもしれないことを経験できたし……","ENG":"Either way, I was able to experience things I probably never could otherwise...","TWN":"不過多虧這樣，我才能夠體驗到也許一輩子都無法體驗到的事……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"낭떠러지처럼 추락하기만 하던 삶에서 새로운 희망을 찾을 수 있었으니까.","JPN":"失敗ばかりの人生から、新たな希望を見つけることができた。","ENG":"And I found hope from a life that felt like an endless pitfall.","TWN":"宛如從斷崖上不斷墜落的生活中，我又能看到新的希望。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"그래서 사장님에게 언젠가 보답을 하고 싶었어.","JPN":"だから、社長にいつかお礼をしたかったんだ。","ENG":"So I always wanted to pay you back for all this.","TWN":"所以，我一直想要報答你，老闆。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"마침 사장님이 이런 제안을 해줘서 기뻤어.","JPN":"ちょうど社長からこんな提案をしてくれて嬉しかった。","ENG":"And I'm really glad you made me this offer.","TWN":"正好老闆提出了這樣的提議，我感到很開心。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"아직 부족한 점이 많겠지만 잘 부탁할게.","JPN":"まだまだ未熟者だけど、よろしくね。","ENG":"I know I still have a lot to improve, but I hope I'll make it worth your while.","TWN":"雖然我還有很多不足之處，但以後也請你多多指教。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"이젠 더는 망설이지 않을 거고,","JPN":"これ以上迷うことなく、","ENG":"I won't hesitate anymore.","TWN":"以後我不會再猶豫不決了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"남겨졌다고 좌절하지도 않을 거야.","JPN":"残されたとしても落ち込んだりしない。","ENG":"And I won't feel sorry for myself for being left behind.","TWN":"也不會再因為被留下而受挫了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"언젠가 나처럼 목적 없이 방황하는 사람을 만났을 때,","JPN":"いつか私みたいに目的もなく迷ってる人に出会った時、","ENG":"One day, when I meet someone who seems as lost as I was...","TWN":"要是有一天，遇到像我一樣漫無目的，不斷彷徨的人……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"그땐, 내가 먼저 그 손을 잡아 이끌어주고 싶어.","JPN":"その時は私が手を差し伸べて導いてあげたいんだ。","ENG":"I want to be the one to reach out first then.","TWN":"那時候，我想要當第一個牽起他的手，帶領他的人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"그러니까,","JPN":"だから、","ENG":"So...","TWN":"所以……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_1BIRTH","text":{"KOREA":"앞으로도 나와 함께 해줘.","JPN":"これからも私と一緒にいてほしい。","ENG":"Stay by my side, as you have.","TWN":"以後也請跟我在一起吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_1BIRTH","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};